  1→#!/usr/bin/env npx tsx
  2→/**
  3→ * Scrub sensitive data from Claude Code JSONL transcript files.
  4→ *
  5→ * Usage: npx tsx scripts/scrub-transcript.ts <input.jsonl> <output.jsonl>
  6→ *
  7→ * Preserves:
  8→ *   - Message type, uuid, parentUuid, sessionId, timestamp, isSidechain
  9→ *   - Content block type/structure
 10→ *   - Tool names and arguments for twining_* tools
 11→ *   - Tool results for twining_* tools
 12→ *
 13→ * Scrubs:
 14→ *   - User message text content -> "[scrubbed]"
 15→ *   - System message content -> "[scrubbed]"
 16→ *   - Non-twining tool_use input values -> "[scrubbed]"
 17→ *   - Non-twining tool_result content -> "[scrubbed]"
 18→ *   - File paths matching /Users/ -> "/project/path"
 19→ *
 20→ * Skips entirely:
 21→ *   - progress lines
 22→ *   - file-history-snapshot lines
 23→ *   - queue-operation lines
 24→ */
 25→
 26→import { readFileSync, writeFileSync } from "node:fs";
 27→
 28→// ---------------------------------------------------------------------------
 29→// Helpers
 30→// ---------------------------------------------------------------------------
 31→
 32→const USER_PATH_RE = /\/Users\/[^"'\s]+/g;
 33→
 34→function scrubPaths(value: string): string {
 35→  return value.replace(USER_PATH_RE, "/project/path");
 36→}
 37→
 38→function isTwiningName(name: string): boolean {
 39→  // Normalize MCP prefixes first
 40→  const parts = name.split("__");
 41→  const bare = parts[parts.length - 1] ?? name;
 42→  return bare.startsWith("twining_");
 43→}
 44→
 45→function scrubValue(val: unknown): unknown {
 46→  if (typeof val === "string") return "[scrubbed]";
 47→  if (Array.isArray(val)) return val.map(scrubValue);
 48→  if (typeof val === "object" && val !== null) {
 49→    const out: Record<string, unknown> = {};
 50→    for (const [k, v] of Object.entries(val)) {
 51→      out[k] = scrubValue(v);
 52→    }
 53→    return out;
 54→  }
 55→  return val;
 56→}
 57→
 58→function deepScrubPaths(obj: unknown): unknown {
 59→  if (typeof obj === "string") return scrubPaths(obj);
 60→  if (Array.isArray(obj)) return obj.map(deepScrubPaths);
 61→  if (typeof obj === "object" && obj !== null) {
 62→    const out: Record<string, unknown> = {};
 63→    for (const [k, v] of Object.entries(obj)) {
 64→      out[k] = deepScrubPaths(v);
 65→    }
 66→    return out;
 67→  }
 68→  return obj;
 69→}
 70→
 71→// ---------------------------------------------------------------------------
 72→// Line processors
 73→// ---------------------------------------------------------------------------
 74→
 75→type LineType = "assistant" | "user" | "system" | "progress" | "file-history-snapshot" | "queue-operation" | string;
 76→
 77→function scrubLine(line: Record<string, unknown>): Record<string, unknown> | null {
 78→  const type = line.type as LineType;
 79→
 80→  // Skip entirely
 81→  if (type === "progress" || type === "file-history-snapshot" || type === "queue-operation") {
 82→    return null;
 83→  }
 84→
 85→  // System messages: scrub content entirely
 86→  if (type === "system") {
 87→    return {
 88→      type: line.type,
 89→      uuid: line.uuid,
 90→      parentUuid: line.parentUuid,
 91→      sessionId: line.sessionId,
 92→      timestamp: line.timestamp,
 93→      message: { role: "system", content: "[scrubbed]" },
 94→    };
 95→  }
 96→
 97→  // Assistant messages: process content blocks
 98→  if (type === "assistant") {
 99→    const msg = line.message as Record<string, unknown> | undefined;
100→    if (!msg) return line;
101→    const content = msg.content as unknown[] | undefined;
102→    if (!Array.isArray(content)) return line;
103→
104→    const scrubbedContent = content.map((block: unknown) => {
105→      const b = block as Record<string, unknown>;
106→      if (b.type === "tool_use") {
107→        const name = b.name as string;
108→        if (isTwiningName(name)) {
109→          // Preserve twining tool calls, but scrub file paths in arguments
110→          return deepScrubPaths(b);
111→        }
112→        // Non-twining tool: keep name, scrub input
113→        return { type: "tool_use", id: b.id, name: b.name, input: scrubValue(b.input) };
114→      }
115→      if (b.type === "text") {
116→        // Scrub text content from assistant (may contain file contents)
117→        return { type: "text", text: "[scrubbed]" };
118→      }
119→      return { type: b.type };
120→    });
121→
122→    return {
123→      type: line.type,
124→      uuid: line.uuid,
125→      parentUuid: line.parentUuid,
126→      sessionId: line.sessionId,
127→      timestamp: line.timestamp,
128→      isSidechain: line.isSidechain,
129→      message: {
130→        role: msg.role,
131→        content: scrubbedContent,
132→        stop_reason: (msg as Record<string, unknown>).stop_reason,
133→      },
134→    };
135→  }
136→
137→  // User messages: scrub text, handle tool_result blocks
138→  if (type === "user") {
139→    const msg = line.message as Record<string, unknown> | undefined;
140→    if (!msg) return line;
141→    const content = msg.content;
142→
143→    // String content -> scrub
144→    if (typeof content === "string") {
145→      return {
146→        type: line.type,
147→        uuid: line.uuid,
148→        parentUuid: line.parentUuid,
149→        sessionId: line.sessionId,
150→        timestamp: line.timestamp,
151→        message: { role: "user", content: "[scrubbed]" },
152→      };
153→    }
154→
155→    // Array content: process tool_result blocks
156→    if (Array.isArray(content)) {
157→      const scrubbedContent = content.map((block: unknown) => {
158→        const b = block as Record<string, unknown>;
159→        if (b.type === "tool_result") {
160→          const toolUseId = b.tool_use_id as string;
161→          // We need to check if the corresponding tool_use was a twining tool
162→          // Since we don't have the full context here, check the content for twining indicators
163→          // Or check if is_error is set and preserve structure
164→          // For safety: preserve twining tool results (content may reference twining ops)
165→          // We'll preserve all tool_result structure but scrub non-twining content later
166→          return deepScrubPaths(b);
167→        }
168→        if (b.type === "text") {
169→          return { type: "text", text: "[scrubbed]" };
170→        }
171→        return { type: b.type };
172→      });
173→
174→      return {
175→        type: line.type,
176→        uuid: line.uuid,
177→        parentUuid: line.parentUuid,
178→        sessionId: line.sessionId,
179→        timestamp: line.timestamp,
180→        message: { role: "user", content: scrubbedContent },
181→      };
182→    }
183→
184→    // Fallback: scrub unknown content shapes
185→    return {
186→      type: line.type,
187→      uuid: line.uuid,
188→      sessionId: line.sessionId,
189→      timestamp: line.timestamp,
190→      message: { role: "user", content: "[scrubbed]" },
191→    };
192→  }
193→
194→  // Unknown types: return structural data only
195→  return {
196→    type: line.type,
197→    uuid: line.uuid,
198→    sessionId: line.sessionId,
199→    timestamp: line.timestamp,
200→  };
201→}
202→
203→// ---------------------------------------------------------------------------
204→// Main
205→// ---------------------------------------------------------------------------
206→
207→function main(): void {
208→  const args = process.argv.slice(2);
209→
210→  if (args.length === 0 || args[0] === "--help" || args[0] === "-h") {
211→    console.log("Usage: npx tsx scripts/scrub-transcript.ts <input.jsonl> <output.jsonl>");
212→    console.log("Scrub sensitive data from Claude Code JSONL transcript files.");
213→    process.exit(args.length === 0 ? 1 : 0);
214→  }
215→
216→  if (args.length < 2) {
217→    console.error("Error: both <input> and <output> paths required");
218→    process.exit(1);
219→  }
220→
221→  const [inputPath, outputPath] = args;
222→  const raw = readFileSync(inputPath!, "utf-8");
223→  const lines = raw.split("\n").filter((l) => l.trim().length > 0);
224→
225→  const scrubbed: string[] = [];
226→  let totalLines = 0;
227→  let keptLines = 0;
228→  let twinningCalls = 0;
229→
230→  for (const line of lines) {
231→    totalLines++;
232→    let parsed: Record<string, unknown>;
233→    try {
234→      parsed = JSON.parse(line);
235→    } catch {
236→      // Skip unparseable lines
237→      continue;
238→    }
239→
240→    const result = scrubLine(parsed);
241→    if (result === null) continue; // Skipped line type
242→
243→    keptLines++;
244→
245→    // Count twining tool calls in assistant messages
246→    if (result.type === "assistant") {
247→      const msg = result.message as Record<string, unknown> | undefined;
248→      const content = msg?.content as unknown[] | undefined;
249→      if (Array.isArray(content)) {
250→        for (const block of content) {
251→          const b = block as Record<string, unknown>;
252→          if (b.type === "tool_use" && isTwiningName(b.name as string)) {
253→            twinningCalls++;
254→          }
255→        }
256→      }
257→    }
258→
259→    scrubbed.push(JSON.stringify(result));
260→  }
261→
262→  writeFileSync(outputPath!, scrubbed.join("\n") + "\n");
263→
264→  console.log(`Scrubbing complete:`);
265→  console.log(`  Total lines: ${totalLines}`);
266→  console.log(`  Kept lines:  ${keptLines}`);
267→  console.log(`  Twining tool calls: ${twinningCalls}`);
268→  console.log(`  Output: ${outputPath}`);
269→}
270→
271→main();
