  1→/**
  2→ * Transcript eval runner: loads manifest fixtures, parses them with the
  3→ * transcript analyzer, and scores with all 7 deterministic scorers.
  4→ *
  5→ * This is the main entry point for `npm run eval:transcript`. It:
  6→ * 1. Reads test/eval/transcript-manifest.json to discover fixtures
  7→ * 2. For each fixture, reads the JSONL file and calls parseTranscript()
  8→ * 3. For each segment x scorer combination, runs the scorer
  9→ * 4. Uses a lower threshold (0.6) for transcript pass/fail vs synthetic (0.8)
 10→ * 5. Writes accumulated results to test/eval/results/transcript-latest.json
 11→ *
 12→ * Same 7 scorers as eval-runner.eval.ts — proving EVAL-05 (scorer reuse
 13→ * across synthetic scenarios and real transcripts).
 14→ */
 15→import { describe, it, expect, beforeAll, afterAll } from "vitest";
 16→import fs from "node:fs";
 17→import path from "node:path";
 18→import { parseTranscript } from "./transcript-analyzer.js";
 19→import { allScorers } from "./scorers/index.js";
 20→import { parseBehaviors } from "./behaviors-parser.js";
 21→import type { BehaviorSpec } from "./types.js";
 22→import type { ScorerResult } from "./scorer-types.js";
 23→
 24→// ---------------------------------------------------------------------------
 25→// Manifest types
 26→// ---------------------------------------------------------------------------
 27→
 28→interface TranscriptFixture {
 29→  file: string;
 30→  description: string;
 31→  expectedQuality: "good" | "poor" | "mixed";
 32→  tags: string[];
 33→}
 34→
 35→interface TranscriptManifest {
 36→  fixtures: TranscriptFixture[];
 37→  thresholds?: { default: number };
 38→}
 39→
 40→// ---------------------------------------------------------------------------
 41→// Load manifest at collection time
 42→// ---------------------------------------------------------------------------
 43→
 44→const manifestPath = path.resolve(
 45→  import.meta.dirname!,
 46→  "transcript-manifest.json",
 47→);
 48→const manifest: TranscriptManifest = JSON.parse(
 49→  fs.readFileSync(manifestPath, "utf-8"),
 50→);
 51→const threshold = manifest.thresholds?.default ?? 0.6;
 52→
 53→// ---------------------------------------------------------------------------
 54→// Results accumulator
 55→// ---------------------------------------------------------------------------
 56→
 57→interface FixtureResults {
 58→  fixture: string;
 59→  expectedQuality: string;
 60→  segments: SegmentResults[];
 61→}
 62→
 63→interface SegmentResults {
 64→  segment: string;
 65→  callCount: number;
 66→  results: ScorerResult[];
 67→}
 68→
 69→const accumulated: FixtureResults[] = [];
 70→
 71→// ---------------------------------------------------------------------------
 72→// Test suite
 73→// ---------------------------------------------------------------------------
 74→
 75→describe("transcript eval suite", () => {
 76→  let spec: BehaviorSpec;
 77→
 78→  beforeAll(() => {
 79→    const behaviorsPath = path.resolve(
 80→      import.meta.dirname!,
 81→      "../../plugin/BEHAVIORS.md",
 82→    );
 83→    const markdown = fs.readFileSync(behaviorsPath, "utf-8");
 84→    spec = parseBehaviors(markdown);
 85→  });
 86→
 87→  for (const fixture of manifest.fixtures) {
 88→    describe(fixture.file, () => {
 89→      // Load and parse the JSONL fixture
 90→      const fixturePath = path.resolve(import.meta.dirname!, fixture.file);
 91→      const jsonlContent = fs.readFileSync(fixturePath, "utf-8");
 92→      const parseResult = parseTranscript(jsonlContent);
 93→
 94→      // Track fixture results
 95→      const fixtureResult: FixtureResults = {
 96→        fixture: fixture.file,
 97→        expectedQuality: fixture.expectedQuality,
 98→        segments: [],
 99→      };
100→      accumulated.push(fixtureResult);
101→
102→      for (let segIdx = 0; segIdx < parseResult.segments.length; segIdx++) {
103→        const segment = parseResult.segments[segIdx]!;
104→        const segmentLabel = `segment ${segIdx} (${segment.calls.length} calls)`;
105→
106→        // Track segment results
107→        const segmentResult: SegmentResults = {
108→          segment: segmentLabel,
109→          callCount: segment.calls.length,
110→          results: [],
111→        };
112→        fixtureResult.segments.push(segmentResult);
113→
114→        describe(segmentLabel, () => {
115→          for (const scorer of allScorers) {
116→            it(scorer.name, async () => {
117→              const result = await scorer.score(segment, spec);
118→
119→              // Accumulate result (individual scorer tests always pass --
120→              // per-scorer threshold enforcement on real transcripts is too
121→              // strict; we assert on average score per fixture instead)
122→              segmentResult.results.push(result);
123→            });
124→          }
125→        });
126→      }
127→    });
128→  }
129→
130→  // -------------------------------------------------------------------------
131→  // Aggregate assertions: good fixtures should score higher than poor on avg
132→  // -------------------------------------------------------------------------
133→
134→  it("good-quality fixtures score >= threshold on average", () => {
135→    const goodFixtures = accumulated.filter(
136→      (f) => f.expectedQuality === "good",
137→    );
138→    for (const fix of goodFixtures) {
139→      const allSegScores = fix.segments.flatMap((seg) =>
140→        seg.results.map((r) => r.score),
141→      );
142→      if (allSegScores.length === 0) continue;
143→      const avg =
144→        allSegScores.reduce((a, b) => a + b, 0) / allSegScores.length;
145→      expect(
146→        avg,
147→        `Good fixture "${fix.fixture}" average score ${avg.toFixed(4)} should be >= ${threshold}`,
148→      ).toBeGreaterThanOrEqual(threshold);
149→    }
150→  });
151→
152→  it("good-quality fixtures score higher than poor-quality fixtures on average", () => {
153→    const avgByQuality = (quality: string): number => {
154→      const fixes = accumulated.filter((f) => f.expectedQuality === quality);
155→      const scores = fixes.flatMap((f) =>
156→        f.segments.flatMap((seg) => seg.results.map((r) => r.score)),
157→      );
158→      return scores.length > 0
159→        ? scores.reduce((a, b) => a + b, 0) / scores.length
160→        : 0;
161→    };
162→
163→    const goodAvg = avgByQuality("good");
164→    const poorAvg = avgByQuality("poor");
165→    expect(
166→      goodAvg,
167→      `Good avg (${goodAvg.toFixed(4)}) should be > poor avg (${poorAvg.toFixed(4)})`,
168→    ).toBeGreaterThan(poorAvg);
169→  });
170→
171→  afterAll(() => {
172→    // Build results JSON in same format as eval-runner.eval.ts
173→    const scenarioResults = accumulated.flatMap((fix) =>
174→      fix.segments.map((seg) => {
175→        const scores: Record<
176→          string,
177→          {
178→            score: number;
179→            passed: boolean;
180→            checks_passed: number;
181→            checks_total: number;
182→          }
183→        > = {};
184→
185→        for (const r of seg.results) {
186→          scores[r.scorer] = {
187→            score: r.score,
188→            passed: r.passed,
189→            checks_passed: r.checks.filter((c) => c.passed).length,
190→            checks_total: r.checks.length,
191→          };
192→        }
193→
194→        return {
195→          name: `${fix.fixture} / ${seg.segment}`,
196→          category: fix.expectedQuality,
197→          scores,
198→        };
199→      }),
200→    );
201→
202→    const allResults = scenarioResults.flatMap((s) =>
203→      Object.values(s.scores),
204→    );
205→    const totalChecks = allResults.reduce(
206→      (sum, r) => sum + r.checks_total,
207→      0,
208→    );
209→    const passedChecks = allResults.reduce(
210→      (sum, r) => sum + r.checks_passed,
211→      0,
212→    );
213→    const allScores = allResults.map((r) => r.score);
214→    const overallScore =
215→      allScores.length > 0
216→        ? Math.round(
217→            (allScores.reduce((a, b) => a + b, 0) / allScores.length) * 10000,
218→          ) / 10000
219→        : 0;
220→
221→    const output = {
222→      timestamp: new Date().toISOString(),
223→      threshold,
224→      summary: {
225→        total_scenarios: scenarioResults.length,
226→        total_checks: totalChecks,
227→        passed_checks: passedChecks,
228→        overall_score: overallScore,
229→      },
230→      scenarios: scenarioResults,
231→    };
232→
233→    // Write results
234→    const resultsDir = path.resolve(import.meta.dirname!, "results");
235→    if (!fs.existsSync(resultsDir)) {
236→      fs.mkdirSync(resultsDir, { recursive: true });
237→    }
238→    const resultsPath = path.resolve(resultsDir, "transcript-latest.json");
239→    fs.writeFileSync(resultsPath, JSON.stringify(output, null, 2));
240→  });
241→});
